    <text x="181" y="126" fill="#e4e4e7" font-size="14" text-anchor="middle">Test: rights = stock → security</text>
    <text x="181" y="158" fill="#e4e4e7" font-size="13" text-anchor="middle">Basis: Capital Markets Act (substance)</text>
    <text x="181" y="190" fill="#e4e4e7" font-size="14" text-anchor="middle">Tax: dividend income tax, etc.</text>
    <text x="181" y="222" fill="#e4e4e7" font-size="13" text-anchor="middle">Gap: offshore tracking</text>
    <text x="181" y="266" fill="#fbbf24" font-size="13" text-anchor="middle">→ Single test, less flexibility</text>
    <text x="181" y="330" fill="#71717a" font-size="13" text-anchor="middle">Announced: 2026-07-09</text>

    <rect x="361" y="55" width="315" height="300" rx="10" fill="#1c1c1f" stroke="#38bdf8" stroke-width="1.5"/>
    <text x="518" y="88" fill="#38bdf8" font-size="15" font-weight="700" text-anchor="middle">US SEC / CFTC</text>
    <text x="518" y="126" fill="#e4e4e7" font-size="14" text-anchor="middle">Classes: 4-category system</text>
    <text x="518" y="158" fill="#e4e4e7" font-size="13" text-anchor="middle">Basis: joint SEC-CFTC interpretation</text>
    <text x="518" y="190" fill="#e4e4e7" font-size="12" text-anchor="middle">Classes: commodity/security/collectible/stablecoin</text>
    <text x="518" y="222" fill="#e4e4e7" font-size="13" text-anchor="middle">Feature: hybrid boundary disputes</text>
    <text x="518" y="266" fill="#fbbf24" font-size="13" text-anchor="middle">→ Multi-category, boundary disputes</text>
    <text x="518" y="330" fill="#71717a" font-size="13" text-anchor="middle">Announced: March 2026</text>
  </g>
  <text x="350" y="382" fill="#71717a" font-size="12" text-anchor="middle" font-family="sans-serif">Sources: Bloomingbit, The Block, SEC-CFTC joint interpretation (as of July 2026)</text>
</svg>
</div>
